<template>
  <div class="main-container">
    <!-- 用户信息 -->
    <Header ref="headerRef" @handleRecharge="handleRecharge" @handleSetting="handleSetting" />

    <!-- 顶部长图 -->
    <MainHeaderImg ref="mainHeaderImgRef" />

    <!-- 导航栏 -->
    <MainNav ref="mainNavRef" @handleSwitchNav="handleSwitchNav" />

    <!-- 页面内容区，根据 page 切换 -->
    <component
      ref="currentComponentRef"
      :categoryParentId="categoryParentId"
      :is="currentPageComponent"
      :vipPackageList="vipPackageList"
      :localMaterialImg="localMaterialImg"
      :lasterVersion="lasterVersion"
      :currentVersion="currentVersion"
      :userInfo="userInfo"
      @refreshUserInfo="refreshUserInfo"
      @handleRecharge="handleRecharge"
    />

    <!-- 强制更新 -->
    <VersionUpdate ref="versionUpdateRef" :forceUpdate="forceUpdate" :lasterVersion="lasterVersion" :currentVersion="currentVersion" />

    <!-- 海报 -->
    <Poster ref="posterRef" :posterStatus="posterStatus" :posterUrl="posterUrl" />

    <!-- 充值弹窗 -->
    <RechargeDialog ref="rechargeDialogRef" coinTitle="" @refreshUserInfo="refreshUserInfo" />

    <!-- 设置弹窗 -->
    <SettingDialog ref="settingDialogRef" @refreshLocalFile="refreshUserInfo" />
  </div>
</template>

<script>
import Header from '@/components/Header.vue';
import MainHeaderImg from '@/components/MainHeaderImg.vue';
import AddMaterial from '@/views/templateone/AddMaterial.vue';
import LocalMaterial from '@/views/templateone/LocalMaterial.vue';
import PsdFile from '@/views/templateone/PsdFile.vue';
import MoreService from '@/views/templateone/MoreService.vue';
import ImportFile from '@/views/templateone/ImportFile.vue';
import SourceFile from '@/views/templateone/SourceFile.vue';
import RechargeDialog from '@/components/RechargeDialog.vue';
import SettingDialog from '@/components/SettingDialog.vue';
import MainNav from '@/components/MainNav.vue';
import Poster from '@/components/Poster.vue';
import VersionUpdate from '@/components/VersionUpdate.vue';
import MaterialList from '@/views/templatetwo/MaterialList.vue';
import LocalMaterialTwo from '@/views/templatetwo/LocalMaterialTwo.vue';
import Tool from '@/views/templatetwo/Tool.vue';
import { getMemUserInfo, getLatestVersion, getMultiConfig } from '@/api/main';
import { getToken, removeToken } from '@/utils/auth';
import { startCepSpy, getPluginVersion } from '@/utils/cepspy';
import { toBoolean } from '@/utils/common';
import { openExternalLink } from '@/utils/cepInterface';

export default {
  name: 'Main',
  components: {
    Header,
    MainHeaderImg,
    AddMaterial,
    LocalMaterial,
    PsdFile,
    MoreService,
    ImportFile,
    SourceFile,
    RechargeDialog,
    SettingDialog,
    Poster,
    VersionUpdate,
    MaterialList,
    LocalMaterialTwo,
    Tool,
    MainNav
  },
  data() {
    return {
      activePage: '',
      userInfo: {},
      coinPackageList: [],
      rechargeHeaderStatus: false,
      rechargeHeaderImg: null,
      versionHistoryUrl: null,
      vipPackageList: [],
      posterStatus: false,
      posterUrl: null,
      forceUpdate: false,
      currentVersion: null,
      lasterVersion: null,
      categoryParentId: '',
      localMaterialImg: null
    };
  },
  mounted() {
    startCepSpy();
  },
  computed: {
    currentPageComponent() {
      const pageMap = {
        'addmaterial': 'AddMaterial',
        'localmaterial': 'LocalMaterial',
        'psdfile': 'PsdFile',
        'moreservice': 'MoreService',
        'importfile': 'ImportFile',
        'sourcefile': 'SourceFile',
        'materiallist': 'MaterialList',
        'localmaterialtwo': 'LocalMaterialTwo',
        'tool': 'Tool'
      };
      return pageMap[this.activePage.toLowerCase()] || this.activePage;
    }
  },
  created() {
    if (!getToken()) {
      this.userExit();
      return;
    }
    this.getUserInfo();
    this.getConfig();
  },
  methods: {
    handleSwitchNav(data) {
      this.activePage = data.activePage;
      this.categoryParentId = data.categoryParentId;
    },
    getUserInfo() {
      // 获取用户信息
      getMemUserInfo().then((response) => {
        this.userInfo = response.data;
      });
    },
    getConfig() {
      let params = {
        codeList: [
          'sys.vipConfig',
          'sys.slideShow',
          'sys.versionHistoryUrl',
          'sys.recharge.config',
          'sys.recharge',
          'sys.poster',
          'sys.menulist',
          'sys.forcedUpdate',
          'sys.localMaterial.img',
          'sys.main.header'
        ]
      };
      // 获取配置信息
      Promise.all([getLatestVersion(), getMultiConfig(params)]).then(([versionInfo, multiConfig]) => {
        this.menuList = JSON.parse(multiConfig.data['sys.menulist']) || this.menuList;
        this.activePage = this.menuList.find((item) => item.defaultShow === true).pageSign;

        this.forceUpdate = toBoolean(multiConfig.data['sys.forcedUpdate']);
        this.lasterVersion = versionInfo.data;
        this.currentVersion = getPluginVersion();
        this.versionHistoryUrl = multiConfig.data['sys.versionHistoryUrl'];
        let posterConfig = JSON.parse(multiConfig.data['sys.poster']) || {};
        this.posterStatus = toBoolean(posterConfig.status || false);
        this.posterUrl = posterConfig.url || '';
        this.vipPackageList = JSON.parse(multiConfig.data['sys.vipConfig']) || [];
        let rechargeConfig = JSON.parse(multiConfig.data['sys.recharge']) || {};
        this.rechargeHeaderStatus = toBoolean(rechargeConfig.status || false);
        this.rechargeHeaderImg = rechargeConfig.url || '';
        this.coinPackageList = JSON.parse(multiConfig.data['sys.recharge.config']) || [];
        this.localMaterialImg = multiConfig.data['sys.localMaterial.img'] || '';
      });
    },
    handleRecharge() {
      this.$refs.rechargeDialogRef.handleOpen(true, this.userInfo, this.rechargeHeaderStatus, this.rechargeHeaderImg, this.coinPackageList);
    },
    handleSetting() {
      this.$refs.settingDialogRef.handleOpen(true);
    },
    openBrowser(url) {
      // 打开外部链接
      if (url) {
        openExternalLink(url);
      }
    },
    userExit() {
      removeToken();
      this.$router.push({ name: 'Login' });
    },
    handleRefreshComponent() {
      // 当设置对话框提交后，如果当前是本地素材页面，则刷新它
      if (this.activePage === 'LocalMaterial' || this.activePage === 'LocalMaterialTwo') {
        this.$nextTick(() => {
          const componentRef = this.$refs.currentComponentRef;
          if (componentRef && componentRef.refreshLocalMaterial) {
            componentRef.refreshLocalMaterial();
          }
        });
      } else if (this.activePage === 'PsdFile') {
        this.$nextTick(() => {
          const componentRef = this.$refs.currentComponentRef;
          if (componentRef && componentRef.refreshPsdFile) {
            componentRef.refreshPsdFile();
          }
        });
      }
    },
    refreshUserInfo() {
      // 刷新用户信息
      this.getUserInfo();
      this.handleRefreshComponent();
      this.$refs.headerRef.getUserInfo();
    }
  }
};
</script>

<style scoped>
.main-container {
  background: #330505;
  height: 100vh;
  color: white;
  overflow: hidden;
}
</style>
